='''
const costData = items[0].json;
let totalDailyCost = 0;
const alerts = [];
const costByService = {};

if (costData.ResultsByTime && costData.ResultsByTime.length > 0) {
  for (const result of costData.ResultsByTime) {
    for (const group of result.Groups) {
      const serviceName = group.Keys[0];
      const amount = parseFloat(group.Metrics.BlendedCost.Amount);
      totalDailyCost += amount;
      costByService[serviceName] = (costByService[serviceName] || 0) + amount;
    }
  }
}

// Define your monthly budget threshold
const MONTHLY_BUDGET_THRESHOLD = 500; // e.g., $500
const DAILY_SPIKE_THRESHOLD_PERCENT = 20; // e.g., 20% increase from average

// Simple monthly cost projection (very basic, for demonstration)
const daysInMonth = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
const currentDayOfMonth = new Date().getDate();
const projectedMonthlyCost = (totalDailyCost / currentDayOfMonth) * daysInMonth;

if (projectedMonthlyCost > MONTHLY_BUDGET_THRESHOLD) {
  alerts.push(`🚨 Projected monthly cost (${projectedMonthlyCost.toFixed(2)}$) exceeds budget threshold (${MONTHLY_BUDGET_THRESHOLD}$).`);
}

// More advanced: Compare with historical average for daily spike
// This would require fetching historical data and storing it,
// or integrating with CloudWatch Alarms for cost anomaly detection.
// For now, a placeholder.
// if (totalDailyCost > (averageDailyCost * (1 + DAILY_SPIKE_THRESHOLD_PERCENT / 100))) {
//   alerts.push(`⚠️ Daily cost (${totalDailyCost.toFixed(2)}$) spiked significantly!`);
// }

return [{ json: { totalDailyCost, projectedMonthlyCost, costByService, alerts, timestamp: new Date().toISOString() } }];
'''

='''
// This is a highly conceptual example. Real implementation would involve:
// 1. Calling AWS APIs (e.g., CloudWatch, EC2, S3, Lambda) to get resource details and metrics.
//    You might need multiple HTTP Request nodes before this Function node, or use AWS SDK in a custom node.
// 2. Applying business logic to identify idle/underutilized resources.
// 3. Generating a list of scaling actions.

const potentialScalingActions = [];

// Example: EC2 instance identification for stopping (conceptual)
// Imagine input from a previous HTTP Request to AWS EC2 ListInstances
const ec2Instances = [
  { instanceId: 'i-0abcdef1234567890', cpuUtilization: 5, tags: { 'AutoScaling': 'true', 'Environment': 'dev' }, state: 'running' },
  { instanceId: 'i-0fedcba9876543210', cpuUtilization: 80, tags: { 'AutoScaling': 'true', 'Environment': 'prod' }, state: 'running' }
];

for (const instance of ec2Instances) {
  if (instance.state === 'running' && instance.cpuUtilization < 10 && instance.tags['AutoScaling'] === 'true' && instance.tags['Environment'] === 'dev') {
    potentialScalingActions.push({
      resourceType: 'EC2',
      action: 'stop',
      instanceId: instance.instanceId,
      reason: `CPU utilization (${instance.cpuUtilization}%) below threshold for dev environment.`
    });
  }
}

// Example: S3 bucket identification for cleanup (conceptual)
// Imagine input from a previous AWS S3 ListFiles node
const s3Buckets = [
  { bucketName: 'my-old-logs', lastModified: new Date('2022-01-01').toISOString(), objectCount: 100000 },
  { bucketName: 'active-data', lastModified: new Date().toISOString(), objectCount: 1000 }
];

const today = new Date();
const threeMonthsAgo = new Date();
threeMonthsAgo.setMonth(today.getMonth() - 3);

for (const bucket of s3Buckets) {
  if (new Date(bucket.lastModified) < threeMonthsAgo && bucket.bucketName.includes('logs')) {
    potentialScalingActions.push({
      resourceType: 'S3',
      action: 'clean_old_objects',
      bucketName: bucket.bucketName,
      reason: `Bucket contains old log data (last modified ${bucket.lastModified})`
    });
  }
}

// Example: Lambda concurrency reduction (conceptual)
// Imagine input from a previous HTTP Request to AWS Lambda GetFunctionConfiguration
const lambdaFunctions = [
  { functionName: 'MyIdleFunction', currentConcurrency: 100, averageInvocations: 5 },
  { functionName: 'MyBusyFunction', currentConcurrency: 1000, averageInvocations: 800 }
];

for (const func of lambdaFunctions) {
  if (func.currentConcurrency > func.averageInvocations * 2 && func.averageInvocations < 10) {
    potentialScalingActions.push({
      resourceType: 'Lambda',
      action: 'reduce_concurrency',
      functionName: func.functionName,
      newConcurrency: Math.max(10, Math.ceil(func.averageInvocations * 1.5)), // Set a minimum and dynamic target
      reason: `Lambda function ${func.functionName} has high concurrency (${func.currentConcurrency}) relative to average invocations (${func.averageInvocations}).`
    });
  }
}

return [{ json: { scalingActions: potentialScalingActions, analysisTimestamp: new Date().toISOString() } }];
